def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a full clause (including the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language clause for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                demonym = "American"
            elif low_obj.startswith("the "):
                demonym = obj[4:].strip()
            else:
                demonym = obj
            # Use appropriate article
            article = "an" if demonym[0].lower() in "aeiou" else "a"
            return f"{subj} is {article} {demonym}"
        if p == "occupation":
            return f"{subj} was {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return f"{subj} is retired"
            return f"{subj} is {low}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            return f"{subj} was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    time_str = f"{hrs} hour{'s' if hrs>1 else ''}"
                    if rem:
                        time_str += f" and {rem} minute{'s' if rem!=1 else ''}"
                else:
                    time_str = f"{rem} minute{'s' if rem!=1 else ''}"
                return f"{subj} spent {time_str} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            return f"{subj} was operated by {obj}"
        if p == "commander":
            return f"{subj}'s commander was {obj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "leader":
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"{subj} is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        # Build a clause for each triple; each clause already includes the subject
        clauses = [phrase(subj, t.predicate, t.object) for t in items]

        if not clauses:
            continue

        if len(clauses) == 1:
            sentence = f"{clauses[0]}."
        else:
            # Join all but last with commas, add conjunction before the final clause
            body = ", ".join(clauses[:-1])
            sentence = f"{body}, and {clauses[-1]}."
        sentences.append(sentence)
        sentences.append(sent)

    # Combine sentences for different subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END

